SELECT course_id, course_name, course_type, cover_image, price, points_price,
       creator_type, creator_id, audit_status, status, create_time, update_time
FROM jst_course

    del_flag = '0'

        AND course_name LIKE CONCAT('%', #{courseName}, '%')


        AND course_type = #{courseType}


        AND audit_status = #{auditStatus}


        AND status = #{status}


ORDER BY create_time DESC, course_id DESC
